package internal

import (
	"fmt"
	"math"
	"math/big"
)

// piNumericString is a high-precision PI for NUMERIC/BIGNUMERIC builtins.
const piNumericString = "3."

func PI() (Value, error) {
	return FloatValue(math.Pi), nil
}

func PI_NUMERIC() (Value, error) {
	r := new(big.Rat)
	if _, ok := r.SetString(piNumericString); !ok {
		return nil, fmt.Errorf("pi_numeric: invalid constant")
	}
	return &NumericValue{Rat: r}, nil
}

func PI_BIGNUMERIC() (Value, error) {
	r := new(big.Rat)
	if _, ok := r.SetString(piNumericString + "0"); !ok {
		return nil, fmt.Errorf("pi_bignumeric: invalid constant")
	}
	return &NumericValue{Rat: r, isBigNumeric: true}, nil
}
